import { jsxs, Fragment, jsx } from 'react/jsx-runtime';
import { classNames } from '../../helpers/classnames.js';
import { ThemeScript } from './ThemeScript.js';

const NextThemeProvider = ({ children, theme = 'light', className = '', ...rest }) => {
    const themeClass = theme === 'light' ? 'ds-theme--light' : 'ds-theme--dark';
    // На сервере оборачиваем детей в контейнер с классом темы,
    // чтобы без JS по умолчанию применялась светлая тема.
    // На клиенте ThemeScript дополнительно ставит класс на body.
    return (jsxs(Fragment, { children: [jsx(ThemeScript, { theme: theme }), jsx("div", { className: classNames(themeClass, className), ...rest, children: children })] }));
};

export { NextThemeProvider };
